view-color\";s:7:\"#2baab1\";s:22:\"quickview-border-color\";s:7:\"#d8d8d6\";s:23:\"quickview-color-inverse\";s:7:\"#ffffff\";s:9:\"hot-color\";s:7:\"#62b959\";s:17:\"hot-color-inverse\";s:7:\"#ffffff\";s:10:\"sale-color\";s:7:\"#e27c7c\";s:18:\"sale-color-inverse\";s:7:\"#ffffff\";s:16:\"add-to-cart-font\";a:3:{s:11:\"font-family\";s:9:\"Open Sans\";s:12:\"font-options\";s:0:\"\";s:6:\"google\";s:1:\"1\";}s:8:\"css-code\";s:12489:\"body:not(.home) #main { padding-top: 40px; }\r\n.no-breadcrumbs .left-sidebar, .no-breadcrumbs .right-sidebar { padding-top: 0; }\r\n.footer-wrapper.simple #footer .footer-bottom { padding: 6px 0 21px; }\r\n.floating-menu .nav { display: block; }\r\n.no-breadcrumbs .main-content, body.woocommerce .main-content { padding-top: 0 !important; }\r\n.say-hello .left-content { border-top: 0; }\r\n.say-hello p { margin-bottom: 16px; }\r\n.say-hello .left-content .wpb_wrapper { float: right; max-width: 526px; width: 100%; }\r\n.custom-min-height-zero { min-height: 0; }\r\n.floating-menu .floating-menu-nav-main .menu-item > a > span { text-transform: uppercase; }\r\n/* Intro about and About me */\r\n.custom-btn-style-1 { padding: 5px 18px !important; border-radius: 35px !important; }\r\n.test .custom-btn-style-1 { margin-left: 7px; padding: 5px 18px 6px; }\r\n.custom-about-me-links:after { content: \'\'; display: block; position: absolute; bottom: 0; right: 0; width: 78vw; border-bottom: 1px solid #e2e2e2; z-index: 0; }\r\n.custom-about-me-links .porto-sicon-default { line-height: 1; }\r\n.custom-about-me-links .porto-sicon-title { white-space: nowrap; }\r\n.custom-about-me-links .container .row { justify-content: flex-end }\r\n.about-me-more { display: none; }\r\n.about-me-more.about-me-more-visible { display: block; }\r\n.custom-image-position-2 .vc_single_image-wrapper, .custom-image-position-2 img { width: 100%; }\r\n/* Skills */\r\n.progress.progress-sm, .vc_progress_bar .vc_single_bar.progress.progress-sm, .vc_progress_bar .progress-label { display: inline-block; }\r\n.vc_progress_bar .vc_single_bar.progress.progress-sm, .progress.progress-sm { margin-top: 9px; margin-bottom: 17px; width: 70% !important; height: 3px; }\r\n.vc_progress_bar .progress-label { float: left; width: 30%; font-size: 12.6px; font-weight: 600; color: #2e353e; }\r\n.progress.progress-sm:last-child { margin-bottom: 5px !important; }\r\n.custom-box-details { padding: 35px; box-shadow: 0 30px 90px 0 #dde5ee; }\r\n.custom-list-style-1 { padding: 0; }\r\n.custom-list-style-1 li { list-style: none; }\r\n.custom-list-style-1 li span { text-transform: uppercase; font-weight: 600; font-size: .9em; }\r\n.custom-list-style-1 li span.custom-max-width-1 { min-width: 130px; }\r\n/* Advance Carousel navigation */\r\n.custom-box-shadow .porto-sicon-box { box-shadow: 0 30px 40px -15px #e5edf6; }\r\n.custom-box-shadow .owl-stage-outer { margin: -20px 0 -40px; padding: 20px 0 40px; }\r\n.custom-box-shadow .owl-carousel .owl-dots { margin-top: 55px !important; }\r\n.portfolio-filter li { margin-right: 10px; }\r\n.portfolio-filter li a, #blog .custom-btn-style-2 { background: transparent; border-radius: 35px; color: #1e1e1e !important; text-transform: uppercase; border: 1px solid #d0d3d6; font-weight: 700; padding: 7px 30px; font-size: .9em; transition: ease background 300ms; }\r\n.portfolio-filter li.active a, .portfolio-filter li:hover a { background-color: #ffd93e; border-color: #ffd93e; }\r\n.portfolio .thumb-info.thumb-info-lighten .thumb-info-wrapper:hover:after { background: #ffd93e; opacity: .8; }\r\n.portfolio .thumb-info-plus::before, .portfolio .thumb-info-plus::after { border-color: #2e353e; }\r\n.portfolio .thumb-info-wrapper img { border-radius: 3px; }\r\n.custom-portfolio hr { display: none; }\r\n.custom-portfolio .portfolio-row { margin-top: 24px; }\r\n/* Blog */\r\n.blog-posts .grid-box { padding: 0 0 36px; border: 0; box-shadow: 0 30px 120px 0 #dde5ee; }\r\n.blog-posts .img-thumbnail { width: 100%; overflow: hidden; border-radius: 3px; }\r\n.blog-posts .img-thumbnail:hover img { transform: scale(1.1, 1.1); }\r\n.blog-posts .post-content { padding: 0 45px; }\r\n.blog-posts a { text-decoration: none; }\r\n.blog-posts .post .entry-title { padding-top: 4px; margin-bottom: 9px; }\r\n.blog-posts .entry-title a { color: #1e1e1e; font-weight: 600; font-size: 17.64px; letter-spacing: -.05em; }\r\n.blog-posts .post-excerpt { padding-bottom: 50px; margin-bottom: 10px; border-bottom: 1px solid #f4f4f4; font-size: .9em; color: #767c93; }\r\n.blog-posts .meta-date { padding-left: 45px; color: #2e353e; font-size: 12.6px; font-weight: 600; text-transform: uppercase; }\r\n.blog-posts .meta-date i, .share-links .share-linkedin, .share-links .share-email, .blog-posts .btn-default { display: none; }\r\n.blog-posts .post-share { float: right; margin: 0; padding: 0 35px 0 0; border: 0; }\r\n.custom-share-text { font-size: 12.6px; }\r\n.blog-posts .share-links  { display: inline-block; vertical-align: baseline; }\r\n.blog-posts .share-links a { padding: 0 10px; margin: 0; border-left: 1px solid #bababa; text-indent: 0; width: auto; height: auto; text-transform: uppercase; line-height: 14px; vertical-align: baseline;  background: transparent; font-weight: 600; font-size: 12.6px; }\r\n.blog-posts .share-links a:first-child, .blog-posts .share-links a:last-child { border-left: 0; }\r\n.blog-posts .share-links a:hover { opacity: .7; }\r\n.blog-posts .share-links .share-facebook, .blog-posts .share-links .share-facebook:hover { color: #395b98; }\r\n.blog-posts .share-links .share-twitter, .blog-posts .share-links .share-twitter:hover { color: #2baae1; }\r\n.blog-posts .share-links .share-googleplus, .blog-posts .share-links .share-googleplus:hover { color: #fc5956; }\r\n.blog-posts .share-links a:before { content: none; }\r\n.share-links .tooltip { display: none !important; }\r\n#blog .custom-btn-style-2 { padding: 10px 30px; line-height: 20px; font-size: 12.8px; border-color: #b5b5b5; }\r\n#blog .custom-btn-style-2:hover { background-color: #fdd55c; }\r\n/* Contact form-start */\r\n.wpcf7-submit:hover { background-color: #2d2c2a !important; }\r\n.wpcf7-submit { background-color: #1f1e1c !important; border-color: #1f1e1c !important; line-height: 1.42857 !important; padding: 10px 30px !important; border-radius: 25px !important; font-weight: 600; font-size: 12.8px; }\r\n.main-content { padding-bottom: 0; }\r\n.wpcf7 input[type=\"text\"], .wpcf7 textarea { background: transparent; border: none; border-bottom: 1px solid rgba(0, 0, 0, 0.3); color: #282d36; font-size: 12px; padding: 7px 0; box-shadow: none; width: 100%; }\r\n.wpcf7-textarea { height: 100px; }\r\n#say-hello .wpcf7-form-control::placeholder { font-weight: 600; color: #1e1e1e; }\r\n/* Contact form-end */\r\n/* Footer col2 */\r\n.footer-icons .porto-sicon-box .porto-icon { padding: 10px; border-radius: 50%; }\r\n.footer-icons .porto-sicon-box:hover .porto-icon { background: #ffd93e !important; transition: ease background 300ms; color: #2e353e !important; }\r\n.footer-icons .feature-box-info strong { font-size: 23.8px; }\r\n.footer-icons .custom-label { font-size: 11.2px; line-height: 16px; color: #b7b7b7; }\r\n.footer-icons .porto-just-icon-wrapper { line-height: 1; }\r\n/* Experience*/\r\nsection.exp-timeline .timeline-box .experience-info .from, section.exp-timeline .timeline-box .experience-info .to { display: block; float: none; }\r\n.experience-info .from { margin-bottom: 3px; }\r\nsection.exp-timeline .timeline-box .experience-info p, section.exp-timeline .timeline-box .experience-info .company > span { color: #1e1e1e !important; opacity: 0.8; }\r\nsection.exp-timeline .timeline-box .experience-info p { margin-top: 3px; margin-bottom: 21px; }\r\n.exp-timeline .company-location { margin-top: 2px; }\r\nsection.timeline .timeline-box.right:after { content: none; }\r\n.btn-tertiary { color: #fff; background-color: #403f3d !important; border-color: #403f3d #403f3d !important; }\r\n.btn-tertiary:hover { border-color: #4d4c49 #4d4c49 #333231 !important; background-color: #4d4c49 !important; }\r\n.custom-box-shadow-4 { box-shadow: 0 12px 90px -10px rgba(139, 139, 139, 0.5) !important; }\r\nol, ul { margin-top: 0; margin-bottom: 10px; }\r\nli { line-height: 24px; }\r\n.custom-list-style-1 { padding: 0; }\r\n.custom-list-style-1 li { list-style: none; }\r\n.custom-list-style-1 li span:nth-child(1) { display: inline-block; min-width: 100px; }\r\n.custom-list-style-1 li span { text-transform: uppercase; font-weight: 600; font-size: .9em; }\r\n.skills-section .custom-list-style-1 li span:nth-child(1) { min-width: 130px; }\r\n.custom-text-color-2 { color: #727c93 !important; }\r\n.recomndation .testimonial.testimonial-with-quotes blockquote::after { right: -2px; color: #1e1e1e; }\r\n.recomndation .testimonial.testimonial-with-quotes blockquote::before { left: -2px; color: #1e1e1e; }\r\n.recomndation .testimonial blockquote { padding-left: 30px; padding-top: 2.5rem; padding-bottom: 28px; }\r\n.recomndation .testimonial blockquote p { text-align: left; color: #1e1e1e; }\r\n.recomndation .testimonial-carousel p { font-size: 14px !important; line-height: 1.8 !important; }\r\n.recomndation .testimonial blockquote::before, .recomndation .testimonial blockquote::after { font-family: \'Playfair Display\'; }\r\n.testimonial-author { margin-top: -1px !important; }\r\n.testimonial .testimonial-author strong { position: relative; margin-top: 7px; padding-top: 13px; text-transform: uppercase; }\r\n.recomndation .testimonial-author strong::before { border-top: 1px solid rgba(0, 0, 0, 0.3); content: \" \"; left: 0; position: absolute; top: 3px; width: 100px; }\r\n.recomndation .testimonial .testimonial-author span { font-size: 14px; font-weight: 300; }\r\n.recomndation .testimonial.testimonial-with-quotes .testimonial-author p { margin: 0; padding-left: 70px; text-align: left; }\r\n.recomndation .owl-carousel .owl-dots .owl-dot span { background: transparent none repeat scroll 0 0; border: 2px solid #1e1e1e;