INSERT INTO `wp_posts` VALUES (4,0,'2026-03-21 10:23:40','2026-03-21 10:23:40','<!-- wp:page-list /-->','Navigation','','publish','closed','closed','','navigation','','','2026-03-21 10:23:40','2026-03-21 10:23:40','',0,'http://localhost:8080/?p=4',0,'wp_navigation','',0),(5,1,'2026-03-21 10:28:24','0000-00-00 00:00:00','','Auto Draft','','auto-draft','open','open','','','','','2026-03-21 10:28:24','0000-00-00 00:00:00','',0,'https://demo.example.com/?p=5',0,'post','',0),(8,1,'2017-02-10 00:54:02','2017-02-10 00:54:02','[vc_row wrap_container=\"yes\" el_class=\"home-landing-row\"][vc_column][vc_column_text css=\"\" css_params=\"\"]</p>\r\n<div class=\"home-landing\">\r\n<section class=\"home-landing__hero\">\r\n<div class=\"home-landing__hero-grid\">\r\n<div>\r\n<p class=\"home-landing__eyebrow\">Your Name (Alex Sinyaev) • Senior Full-Stack Engineer</p>\r\n<h1>Building scalable web products with strong backend architecture.</h1>\r\n<p class=\"home-landing__lead\">I design and deliver reliable SaaS systems, internal tools, and product features across Laravel, React, Vue.js, TypeScript, MySQL, AWS, Docker, and CI/CD.</p>\r\n<p class=\"home-landing__summary\">With 10+ years of hands-on experience, I help teams modernize legacy codebases, improve production performance, and ship maintainable software without losing product momentum.</p>\r\n<div class=\"home-landing__actions\"><a class=\"home-landing__button home-landing__button--primary\" href=\"#writing\">Read selected articles</a><br />\r\n<a class=\"home-landing__button\" href=\"#contact\">Contact me</a></div>\r\n<ul class=\"home-landing__stats\">\r\n<li><strong>10+ years</strong>shipping production web systems</li>\r\n<li><strong>Full-stack</strong>backend, frontend, and delivery ownership</li>\r\n<li><strong>SaaS focus</strong>scalable apps, billing, performance, integrations</li>\r\n</ul>\r\n</div>\r\n<div class=\"home-landing__portrait-wrap\"><p><img class=\"home-landing__portrait\" src=\"/app/uploads/2023/06/profile.jpg\" alt=\"Your Name portrait\"></p>\r\n<div class=\"home-landing__hero-note\"><strong>Current focus</strong><br />\r\nLaravel architecture, product engineering, scalable integrations, and practical delivery workflows.</div>\r\n</div>\r\n</div>\r\n</section>\r\n<section id=\"expertise\" class=\"home-landing__section\">\r\n<div class=\"home-landing__section-head\">\r\n<div>\r\n<p class=\"home-landing__section-eyebrow\">Expertise</p>\r\n<h2>What I do</h2>\r\n</div>\r\n<p class=\"home-landing__section-intro\">I work best in products that need more than isolated coding tasks: backend decisions, frontend implementation, delivery reliability, and measurable business outcomes.</p>\r\n</div>\r\n<div class=\"home-landing__grid home-landing__grid--cards\">\r\n<article class=\"home-landing__card\"><span class=\"home-landing__card-tag\">Backend</span></p>\r\n<h3>Laravel systems that stay maintainable under growth.</h3>\r\n<p>Service boundaries, queues, caching, billing workflows, clean integrations, and predictable code paths for real production use.</p>\r\n</article>\r\n<article class=\"home-landing__card\"><span class=\"home-landing__card-tag\">Frontend</span></p>\r\n<h3>Practical interfaces for dashboards and internal tools.</h3>\r\n<p>React, Vue.js, and TypeScript implementations focused on clarity, performance, and the workflows teams actually need every day.</p>\r\n</article>\r\n<article class=\"home-landing__card\"><span class=\"home-landing__card-tag\">Performance</span></p>\r\n<h3>Optimization that improves real user experience.</h3>\r\n<p>Query tuning, database indexing, Redis, background jobs, and infrastructure decisions that remove bottlenecks instead of hiding them.</p>\r\n</article>\r\n<article class=\"home-landing__card\"><span class=\"home-landing__card-tag\">Delivery</span></p>\r\n<h3>Safer releases and better engineering flow.</h3>\r\n<p>Docker, AWS, CI/CD, code reviews, and engineering discipline that reduce manual overhead and make teams more confident in production.</p>\r\n</article>\r\n</div>\r\n</section>\r\n<section id=\"impact\" class=\"home-landing__section home-landing__section--accent\">\r\n<div class=\"home-landing__section-head\">\r\n<div>\r\n<p class=\"home-landing__section-eyebrow\">Impact</p>\r\n<h2>Selected results</h2>\r\n</div>\r\n<p class=\"home-landing__section-intro\">The strongest work is usually operationally boring after launch: simpler releases, fewer incidents, better performance, and cleaner systems for the next iteration.</p>\r\n</div>\r\n<ul class=\"home-landing__list\">\r\n<li>Modernized deployments by moving manual release routines into automated CI/CD pipelines.</li>\r\n<li>Improved production responsiveness through query optimization, database indexing, and Redis caching.</li>\r\n<li>Built subscription billing and payment workflows with Laravel Cashier and Stripe.</li>\r\n<li>Helped raise engineering quality through reviews, mentoring, and stronger code ownership.</li>\r\n</ul>\r\n</section>\r\n<section id=\"experience\" class=\"home-landing__section\">\r\n<div class=\"home-landing__section-head\">\r\n<div>\r\n<p class=\"home-landing__section-eyebrow\">Experience</p>\r\n<h2>Engineering background</h2>\r\n</div>\r\n<p class=\"home-landing__section-intro\">My strongest work sits at the intersection of product thinking and implementation: legacy modernization, architecture cleanup, delivery improvement, and shipping features that support real business goals.</p>\r\n</div>\r\n<div class=\"home-landing__grid home-landing__grid--cards\">\r\n<article class=\"home-landing__card\"><span class=\"home-landing__card-tag\">Current</span></p>\r\n<h3>Senior Full-Stack Engineer at Your Company.</h3>\r\n<p>Working across SaaS product engineering, frontend delivery, backend systems, content surfaces, and maintainable implementation for a mature writing-assistance platform.</p>\r\n</article>\r\n<article class=\"home-landing__card\"><span class=\"home-landing__card-tag\">Previous</span></p>\r\n<h3>Full-stack and backend work across product and agency environments.</h3>\r\n<p>Building Laravel systems, WordPress platforms, APIs, billing logic, custom plugins, and business-facing tools across different product stages.</p>\r\n</article>\r\n</div>\r\n</section>\r\n<section id=\"stack\" class=\"home-landing__section\">\r\n<div class=\"home-landing__section-head\">\r\n<div>\r\n<p class=\"home-landing__section-eyebrow\">Stack</p>\r\n<h2>Core technologies</h2>\r\n</div>\r\n<p class=\"home-landing__section-intro\">I prefer straightforward tools and clear architecture over fashionable complexity. The stack should help the product move faster, not become the product.</p>\r\n</div>\r\n<ul class=\"home-landing__stack\">\r\n<li>Laravel</li>\r\n<li>PHP</li>\r\n<li>React</li>\r\n<li>Vue.js</li>\r\n<li>TypeScript</li>\r\n<li>JavaScript</li>\r\n<li>MySQL</li>\r\n<li>Redis</li>\r\n<li>Docker</li>\r\n<li>AWS</li>\r\n<li>GitHub Actions</li>\r\n<li>REST APIs</li>\r\n<li>Stripe</li>\r\n<li>PHPUnit</li>\r\n<li>Jest</li>\r\n</ul>\r\n</section>\r\n<section id=\"portfolio\" class=\"home-landing__section\">\r\n<div class=\"home-landing__section-head\">\r\n<div>\r\n<p class=\"home-landing__section-eyebrow\">Portfolio</p>\r\n<h2>Selected product and platform work</h2>\r\n</div>\r\n<p class=\"home-landing__section-intro\">These cases show the kind of work I do best: product-facing engineering, structured content experiences, and implementation that stays maintainable after launch.</p>\r\n</div>\r\n<div class=\"home-landing__grid home-landing__grid--articles\"><a class=\"home-landing__article\" href=\"/portfolio/webspellchecker-product-and-plugin-ecosystem/\"><br />\r\n<img class=\"home-landing__article-image\" src=\"/app/uploads/2024/02/screencapture-webspellchecker-2024-02-24-12_23_17.png\" alt=\"Your Company portfolio preview\"></a></p>\r\n<div class=\"home-landing__article-body\"><p><span class=\"home-landing__article-meta\">SaaS Product</span></p>\r\n<h3>Your Company product and plugin ecosystem</h3>\r\n<p>Product-facing engineering around plugin surfaces, marketing pages, and content structure for a multilingual writing-assistance platform.</p>\r\n</div>\r\n<p>&nbsp;</p>\r\n<p><a class=\"home-landing__article\" href=\"/portfolio/wproofreader-blog-and-content-experience/\"><br />\r\n<img class=\"home-landing__article-image\" src=\"/app/uploads/2024/02/screencapture-blog-wproofreader-2024-02-24-12_24_38.png\" alt=\"WProofreader portfolio preview\"></a></p>\r\n<div class=\"home-landing__article-body\"><p><span class=\"home-landing__article-meta\">Content UX</span></p>\r\n<h3>WProofreader blog and content experience</h3>\r\n<p>Editorial and engineering work focused on blog UX, readable content structure, and stronger SEO-aware presentation.</p>\r\n</div>\r\n<p>&nbsp;</p>\r\n<p><a class=\"home-landing__article\" href=\"/portfolio/slp-test-prep-learning-platform/\"><br />\r\n<img class=\"home-landing__article-image\" src=\"/app/uploads/2024/02/screencapture-slptestprep-2024-02-24-12_20_07.png\" alt=\"SLP Test Prep portfolio preview\"></a></p>\r\n<div class=\"home-landing__article-body\"><p><span class=\"home-landing__article-meta\">Education</span></p>\r\n<h3>SLP Test Prep learning platform</h3>\r\n<p>An education-focused platform where clarity, trust, responsive structure, and conversion-aware presentation all mattered.</p>\r\n</div>\r\n<p>&nbsp;</p>\r\n</div>\r\n</section>\r\n<section id=\"writing\" class=\"home-landing__section\">\r\n<div class=\"home-landing__section-head\">\r\n<div>\r\n<p class=\"home-landing__section-eyebrow\">Writing</p>\r\n<h2>Articles based on real project work</h2>\r\n</div>\r\n<p class=\"home-landing__section-intro\">I write for engineers, founders, and teams who want practical explanations instead of abstract theory. The focus is architecture, integrations, performance, and maintainable implementation.</p>\r\n</div>\r\n<div class=\"home-landing__grid home-landing__grid--articles\"><a class=\"home-landing__article\" href=\"/?p=542&amp;lang=en\"><br />\r\n<img class=\"home-landing__article-image\" src=\"/app/uploads/2023/07/1_1Gol3Pay8vho6Y3lH1SlkQ.png\" alt=\"Dependency injection article cover\"></a></p>\r\n<div class=\"home-landing__article-body\"><p><span class=\"home-landing__article-meta\">Architecture</span></p>\r\n<h3>Dependency Injection and Dependency Inversion in Laravel</h3>\r\n<p>Clear explanation of the difference, why it matters, and how it improves extensibility in real Laravel applications.</p>\r\n</div>\r\n<p>&nbsp;</p>\r\n<p><a class=\"home-landing__article\" href=\"/?p=545&amp;lang=en\"><br />\r\n<img class=\"home-landing__article-image\" src=\"/app/uploads/2023/06/laravel-cashier.jpg\" alt=\"Laravel Cashier article cover\"></a></p>\r\n<div class=\"home-landing__article-body\"><p><span class=\"home-landing__article-meta\">Billing</span></p>\r\n<h3>Laravel subscriptions with Cashier and Stripe</h3>\r\n<p>A practical walkthrough of subscription billing, lifecycle handling, and why Cashier helps reduce payment complexity.</p>\r\n</div>\r\n<p>&nbsp;</p>\r\n<p><a class=\"home-landing__article\" href=\"/?p=547&amp;lang=en\"><br />\r\n<img class=\"home-landing__article-image\" src=\"/app/uploads/2023/03/docker-wordpress.png\" alt=\"Docker and WordPress article cover\"></a></p>\r\n<div class=\"home-landing__article-body\"><p><span class=\"home-landing__article-meta\">Dev Workflow</span></p>\r\n<h3>Docker and WordPress for cleaner local development</h3>\r\n<p>Why containerized workflows reduce environment drift and make WordPress development more consistent across teams.</p>\r\n</div>\r\n<p>&nbsp;</p>\r\n</div>\r\n</section>\r\n<section id=\"contact\" class=\"home-landing__section home-landing__section--contact\">\r\n<div class=\"home-landing__section-head\">\r\n<div>\r\n<p class=\"home-landing__section-eyebrow\">Contact</p>\r\n<h2>Need help with a product or platform rebuild?</h2>\r\n</div>\r\n<p class=\"home-landing__section-intro\">If you are improving an existing system, launching something new, or need a senior engineer who can operate across backend, frontend, and infrastructure, feel free to reach out.</p>\r\n</div>\r\n<div class=\"home-landing__contact-grid\"><a class=\"home-landing__contact-card\" href=\"mailto:your@email.com\"><br />\r\n<strong>Email</strong><br />\r\nyour@email.com<br />\r\n</a><br />\r\n<a class=\"home-landing__contact-card\" href=\"https://www.linkedin.com/in/yourprofile/\" target=\"_blank\" rel=\"noopener noreferrer\"><br />\r\n<strong>LinkedIn</strong><br />\r\nlinkedin.com/in/yourprofile<br />\r\n</a><br />\r\n<a class=\"home-landing__contact-card\" href=\"https://t.me/yourusername\" target=\"_blank\" rel=\"noopener noreferrer\"><br />\r\n<strong>Telegram</strong><br />\r\n@yourusername<br />\r\n</a></div>\r\n</section>\r\n</div>\r\n<p>[/vc_column_text][/vc_column][/vc_row]','Home','','publish','closed','closed','','home','','','2026-03-21 15:00:02','2026-03-21 15:00:02','',0,'http://sw-themes.com/porto_dummy/?page_id=8',0,'page','',0),(9,1,'2026-03-21 10:32:32','2026-03-21 10:32:32','<label> Your name\n    [text* your-name autocomplete:name] </label>\n\n<label> Your email\n    [email* your-email autocomplete:email] </label>\n\n<label> Subject\n    [text* your-subject] </label>\n\n<label> Your message (optional)\n    [textarea your-message] </label>\n\n[submit \"Submit\"]\n[_site_title] \"[your-subject]\"\n[_site_title] <admin@example.com>\nFrom: [your-name] [your-email]\nSubject: [your-subject]\n\nMessage Body:\n[your-message]\n\n-- \nThis is a notification that a contact form was submitted on your website ([_site_title] [_site_url]).\n[_site_admin_email]\nReply-To: [your-email]\n\n0\n0\n\n[_site_title] \"[your-subject]\"\n[_site_title] <admin@example.com>\nMessage Body:\n[your-message]\n\n-- \nThis email is a receipt for your contact form submission on our website ([_site_title] [_site_url]) in which your email address was used. If that was not you, please ignore this message.\n[your-email]\nReply-To: [_sit